import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface FunnelStage {
  stage: string;
  conversionRate: number;
  previousRate: number;
}

interface FunnelData {
  funnelStages: FunnelStage[];
  comparison: {
    current: number[];
    previous: number[];
  };
}

export default function Widget() {
  const funnelData = response.data as FunnelData;
  const { funnelStages, comparison } = funnelData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#303030' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FF5722' }}>
              Conversion Funnel
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: comparison.current,
                  color: '#FF5722',
                  label: 'Current',
                },
                {
                  type: 'bar',
                  data: comparison.previous,
                  color: '#4CAF50',
                  label: 'Previous',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: funnelStages.map(stage => stage.stage),
                  id: 'stages',
                },
              ]}
              yAxis={[{ id: 'conversionRate' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="stages"
                tickLabelStyle={{ fontSize: 10, fill: '#FFFFFF' }}
              />
              <ChartsYAxis
                axisId="conversionRate"
                tickLabelStyle={{ fontSize: 10, fill: '#FFFFFF' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
